import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // History and Speech
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Voice Loading
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const preferred = 
        voices.find(v => v.name.includes('Google US English')) || 
        voices.find(v => v.name.includes('Samantha')) || 
        voices.find(v => v.lang === 'en-US');
      setVoice(preferred || voices[0]);
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => cancelSpeech();
  }, []);

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) return;

    // Just play it, don't toggle if it's a different text request (simplified for quiz components)
    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);
    if (voice) utterance.voice = voice;
    utterance.lang = 'en-US';
    utterance.rate = 0.9;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-4 flex items-center gap-2">
                  <ImageIcon size={16} className="text-blue-500" /> Content Type
                </label>
                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm">Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-3 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // History and Speech
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Voice Loading
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const preferred = 
        voices.find(v => v.name.includes('Google US English')) || 
        voices.find(v => v.name.includes('Samantha')) || 
        voices.find(v => v.lang === 'en-US');
      setVoice(preferred || voices[0]);
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => cancelSpeech();
  }, []);

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) return;

    // Just play it, don't toggle if it's a different text request (simplified for quiz components)
    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);
    if (voice) utterance.voice = voice;
    utterance.lang = 'en-US';
    utterance.rate = 0.9;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-4 flex items-center gap-2">
                  <ImageIcon size={16} className="text-blue-500" /> Content Type
                </label>
                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm">Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-4 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 md:p-5 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // History and Speech
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Voice Loading
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const preferred = 
        voices.find(v => v.name.includes('Google US English')) || 
        voices.find(v => v.name.includes('Samantha')) || 
        voices.find(v => v.lang === 'en-US');
      setVoice(preferred || voices[0]);
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => cancelSpeech();
  }, []);

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) return;

    // Just play it, don't toggle if it's a different text request (simplified for quiz components)
    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);
    if (voice) utterance.voice = voice;
    utterance.lang = 'en-US';
    utterance.rate = 0.9;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-4 flex items-center gap-2">
                  <ImageIcon size={16} className="text-blue-500" /> Content Type
                </label>
                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm">Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-4 md:space-y-6 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 md:p-6 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff,
  Settings,
  Mic
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // Audio Settings
  const [speechRate, setSpeechRate] = useState(1.0);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [selectedVoiceURI, setSelectedVoiceURI] = useState<string>('');
  const [showAudioSettings, setShowAudioSettings] = useState(false);

  // History and Speech State
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.speechRate) setSpeechRate(parsed.speechRate);
        if (parsed.selectedVoiceURI) setSelectedVoiceURI(parsed.selectedVoiceURI);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Voice Loading
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      setAvailableVoices(voices);

      // If we haven't selected a voice yet (or loaded from storage), pick a default
      if (!selectedVoiceURI && voices.length > 0) {
        const preferred = 
          voices.find(v => v.name.includes('Google US English')) || 
          voices.find(v => v.name.includes('Samantha')) || 
          voices.find(v => v.lang === 'en-US');
        if (preferred) setSelectedVoiceURI(preferred.voiceURI);
        else setSelectedVoiceURI(voices[0].voiceURI);
      }
    };

    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => cancelSpeech();
  }, [selectedVoiceURI]); // Re-run if voice URI changes to ensure consistency if voices load late

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      speechRate,
      selectedVoiceURI
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, speechRate, selectedVoiceURI]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) return;

    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);

    // Find the voice object based on the selected URI
    if (selectedVoiceURI) {
      const voiceToUse = availableVoices.find(v => v.voiceURI === selectedVoiceURI);
      if (voiceToUse) utterance.voice = voiceToUse;
    }

    utterance.lang = 'en-US';
    utterance.rate = speechRate;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Audio Settings Toggle */}
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
              <button 
                onClick={() => setShowAudioSettings(!showAudioSettings)}
                className="w-full flex justify-between items-center text-left"
              >
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2 cursor-pointer">
                  <Volume2 size={16} className="text-blue-500" /> Audio Options (Sound AI)
                </label>
                {showAudioSettings ? <ChevronLeft className="rotate-90 text-slate-400" size={18} /> : <ChevronRight className="rotate-90 text-slate-400" size={18} />}
              </button>

              {showAudioSettings && (
                <div className="mt-4 space-y-4 animate-in fade-in slide-in-from-top-1">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">AI Voice</label>
                    <select 
                      value={selectedVoiceURI} 
                      onChange={(e) => setSelectedVoiceURI(e.target.value)}
                      className="w-full p-2 text-sm bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      {availableVoices.map(v => (
                        <option key={v.voiceURI} value={v.voiceURI}>
                          {v.name} ({v.lang})
                        </option>
                      ))}
                      {availableVoices.length === 0 && <option>Loading voices...</option>}
                    </select>
                  </div>

                  <div>
                    <div className="flex justify-between items-center mb-2">
                      <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Speaking Rate</label>
                      <span className="text-xs font-bold text-slate-600">{speechRate}x</span>
                    </div>
                    <input 
                      type="range" 
                      min="0.5" 
                      max="2" 
                      step="0.1" 
                      value={speechRate} 
                      onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>

                  <button 
                    onClick={() => speak("This is a test of the audio settings. Anatomy and Physiology.")}
                    className="w-full py-2 bg-blue-100 hover:bg-blue-200 text-blue-700 rounded-lg text-xs font-bold uppercase flex items-center justify-center gap-2"
                  >
                    <Mic size={14} /> Test Voice
                  </button>
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-4 flex items-center gap-2">
                  <ImageIcon size={16} className="text-blue-500" /> Content Type
                </label>
                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm">Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-4 md:space-y-6 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 md:p-6 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff,
  Settings,
  Mic
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // Audio Settings
  const [speechRate, setSpeechRate] = useState(1.0);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [selectedVoiceURI, setSelectedVoiceURI] = useState<string>('');
  const [showAudioSettings, setShowAudioSettings] = useState(false);

  // History and Speech State
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.speechRate) setSpeechRate(parsed.speechRate);
        if (parsed.selectedVoiceURI) setSelectedVoiceURI(parsed.selectedVoiceURI);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Voice Loading
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      setAvailableVoices(voices);

      // If we haven't selected a voice yet (or loaded from storage), pick a default
      if (!selectedVoiceURI && voices.length > 0) {
        const preferred = 
          voices.find(v => v.name.includes('Google US English')) || 
          voices.find(v => v.name.includes('Samantha')) || 
          voices.find(v => v.lang === 'en-US');
        if (preferred) setSelectedVoiceURI(preferred.voiceURI);
        else setSelectedVoiceURI(voices[0].voiceURI);
      }
    };

    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => cancelSpeech();
  }, [selectedVoiceURI]); // Re-run if voice URI changes to ensure consistency if voices load late

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      speechRate,
      selectedVoiceURI
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, speechRate, selectedVoiceURI]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) return;

    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);

    // Find the voice object based on the selected URI
    if (selectedVoiceURI) {
      const voiceToUse = availableVoices.find(v => v.voiceURI === selectedVoiceURI);
      if (voiceToUse) utterance.voice = voiceToUse;
    }

    utterance.lang = 'en-US';
    utterance.rate = speechRate;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Audio Settings Toggle */}
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
              <button 
                onClick={() => setShowAudioSettings(!showAudioSettings)}
                className="w-full flex justify-between items-center text-left"
              >
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2 cursor-pointer">
                  <Volume2 size={16} className="text-blue-500" /> Audio Options (Sound AI)
                </label>
                {showAudioSettings ? <ChevronLeft className="rotate-90 text-slate-400" size={18} /> : <ChevronRight className="rotate-90 text-slate-400" size={18} />}
              </button>

              {showAudioSettings && (
                <div className="mt-4 space-y-4 animate-in fade-in slide-in-from-top-1">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">AI Voice</label>
                    <select 
                      value={selectedVoiceURI} 
                      onChange={(e) => setSelectedVoiceURI(e.target.value)}
                      className="w-full p-2 text-sm bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      {availableVoices.map(v => (
                        <option key={v.voiceURI} value={v.voiceURI}>
                          {v.name} ({v.lang})
                        </option>
                      ))}
                      {availableVoices.length === 0 && <option>Loading voices...</option>}
                    </select>
                  </div>

                  <div>
                    <div className="flex justify-between items-center mb-2">
                      <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Speaking Rate</label>
                      <span className="text-xs font-bold text-slate-600">{speechRate}x</span>
                    </div>
                    <input 
                      type="range" 
                      min="0.5" 
                      max="2" 
                      step="0.1" 
                      value={speechRate} 
                      onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>

                  <button 
                    onClick={() => speak("This is a test of the audio settings. Anatomy and Physiology.")}
                    className="w-full py-2 bg-blue-100 hover:bg-blue-200 text-blue-700 rounded-lg text-xs font-bold uppercase flex items-center justify-center gap-2"
                  >
                    <Mic size={14} /> Test Voice
                  </button>
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center gap-4">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                  <Settings size={16} className="text-blue-500" /> Display Options
                </label>

                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><ImageIcon size={16} /> Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>

                <button 
                  onClick={() => setShowExplanations(!showExplanations)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showExplanations ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><Lightbulb size={16} /> Show Explanations</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showExplanations ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showExplanations ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-4 md:space-y-6 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 md:p-6 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  Play, 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig,
  LayoutGrid,
  Image as ImageIcon,
  Zap,
  Hash,
  Menu,
  Filter,
  Info,
  CircleCheck,
  CircleX,
  CircleAlert,
  Volume2,
  VolumeX,
  Lightbulb,
  Eye,
  EyeOff,
  Settings,
  Mic
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // Audio Settings
  const [speechRate, setSpeechRate] = useState(1.0);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [selectedVoiceURI, setSelectedVoiceURI] = useState<string>('');
  const [showAudioSettings, setShowAudioSettings] = useState(false);

  // History and Speech State
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const speakingRef = useRef<boolean>(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.speechRate) setSpeechRate(parsed.speechRate);
        if (parsed.selectedVoiceURI) setSelectedVoiceURI(parsed.selectedVoiceURI);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }

    // Robust Voice Loading
    const updateVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      if (voices.length > 0) {
        // Filter unique voices to avoid duplicates in some browsers
        const uniqueVoices = Array.from(new Map(voices.map(v => [v.voiceURI, v])).values());
        setAvailableVoices(uniqueVoices);
      }
    };

    updateVoices();

    // Some browsers need explicit event listeners
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = updateVoices;
    }
    window.speechSynthesis.addEventListener('voiceschanged', updateVoices);

    return () => {
      window.speechSynthesis.removeEventListener('voiceschanged', updateVoices);
      cancelSpeech();
    };
  }, []);

  // Ensure a valid voice is selected when voices load
  useEffect(() => {
    if (availableVoices.length > 0) {
      // Check if currently selected voice still exists
      const currentVoiceExists = availableVoices.some(v => v.voiceURI === selectedVoiceURI);

      if (!selectedVoiceURI || !currentVoiceExists) {
        // Prefer English US voices
        const preferred = 
          availableVoices.find(v => v.name.includes('Google US English')) || 
          availableVoices.find(v => v.name.includes('Samantha')) || 
          availableVoices.find(v => v.lang === 'en-US') || 
          availableVoices.find(v => v.lang.startsWith('en'));

        if (preferred) setSelectedVoiceURI(preferred.voiceURI);
        else setSelectedVoiceURI(availableVoices[0].voiceURI);
      }
    }
  }, [availableVoices, selectedVoiceURI]);

  // Save settings when changed
  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      speechRate,
      selectedVoiceURI
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, speechRate, selectedVoiceURI]);

  // Save session state
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  // Update mistakes when finishing exam
  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id); // Remove if correct now
        } else {
          newMistakes.add(q.id); // Add if incorrect
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancelSpeech();
  }, [currentQIndex]);

  // Derived data
  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  // Adjust question count if max possible changes
  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        // Ensure correct answer is in options if not already (safeguard)
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        // Generate random distractors if none provided
        options = [
          ...data.filter(i => i.answerText && i.answerText !== correct)
                 .sort(() => Math.random() - 0.5)
                 .slice(0, 3)
                 .map(i => i.answerText),
          correct
        ].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60); // 1 min per question
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Speech Functions
  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      speakingRef.current = false;
    }
  };

  const speak = (text: string) => {
    if (!('speechSynthesis' in window)) {
      alert("Your browser does not support text-to-speech.");
      return;
    }

    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);

    // Find the voice object based on the selected URI
    if (selectedVoiceURI) {
      const voiceToUse = availableVoices.find(v => v.voiceURI === selectedVoiceURI);
      if (voiceToUse) utterance.voice = voiceToUse;
    }

    utterance.lang = 'en-US';
    utterance.rate = speechRate;
    utterance.pitch = 1;

    utterance.onstart = () => {
      setIsSpeaking(true);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      speakingRef.current = false;
    };

    window.speechSynthesis.speak(utterance);
  };

  // Timer
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setView('results');
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions.length]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return; // Prevent changing in practice if already answered

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // ----------------------------------------------------------------------
  // Setup View
  // ----------------------------------------------------------------------
  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            {/* Mode Selection */}
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {/* Smart Review Panel */}
            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            {/* Topics Filter */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* Audio Settings Toggle */}
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
              <button 
                onClick={() => setShowAudioSettings(!showAudioSettings)}
                className="w-full flex justify-between items-center text-left"
              >
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2 cursor-pointer">
                  <Volume2 size={16} className="text-blue-500" /> Audio Options (Sound AI)
                </label>
                {showAudioSettings ? <ChevronLeft className="rotate-90 text-slate-400" size={18} /> : <ChevronRight className="rotate-90 text-slate-400" size={18} />}
              </button>

              {showAudioSettings && (
                <div className="mt-4 space-y-4 animate-in fade-in slide-in-from-top-1">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">AI Voice</label>
                    <select 
                      value={selectedVoiceURI} 
                      onChange={(e) => setSelectedVoiceURI(e.target.value)}
                      className="w-full p-2 text-sm bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      {availableVoices.length > 0 ? (
                        availableVoices.map(v => (
                          <option key={v.voiceURI} value={v.voiceURI}>
                            {v.name} ({v.lang})
                          </option>
                        ))
                      ) : (
                        <option>Loading voices (check system permissions)...</option>
                      )}
                    </select>
                  </div>

                  <div>
                    <div className="flex justify-between items-center mb-2">
                      <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Speaking Rate</label>
                      <span className="text-xs font-bold text-slate-600">{speechRate}x</span>
                    </div>
                    <input 
                      type="range" 
                      min="0.5" 
                      max="2" 
                      step="0.1" 
                      value={speechRate} 
                      onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>

                  <button 
                    onClick={() => speak("This is a test of the audio settings. Anatomy and Physiology.")}
                    className="w-full py-2 bg-blue-100 hover:bg-blue-200 text-blue-700 rounded-lg text-xs font-bold uppercase flex items-center justify-center gap-2"
                  >
                    <Mic size={14} /> Test Voice
                  </button>
                </div>
              )}
            </div>

            {/* Sliders and Toggles */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center gap-4">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                  <Settings size={16} className="text-blue-500" /> Display Options
                </label>

                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><ImageIcon size={16} /> Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>

                <button 
                  onClick={() => setShowExplanations(!showExplanations)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showExplanations ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><Lightbulb size={16} /> Show Explanations</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showExplanations ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showExplanations ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Results View
  // ----------------------------------------------------------------------
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            <h4 className="font-semibold text-slate-900 text-base md:text-lg">{q.data.questionText}</h4>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer || "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                {q.correctOption}
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button onClick={() => speak(q.data.explanation || '')} className="text-blue-500 hover:text-blue-700">
                                    <Volume2 size={14} />
                                  </button>
                                </div>
                                <p className="text-sm text-slate-700 leading-relaxed">{q.data.explanation}</p>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Review Mode (Before Submission)
  // ----------------------------------------------------------------------
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // Playing Mode
  // ----------------------------------------------------------------------
  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded bg-slate-100 border border-slate-200 font-mono font-bold text-sm ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-slate-700'}`}>
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar Map */}
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              {/* Progress Bar */}
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {/* Metadata Row */}
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => speak(currentQ.data.questionText)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${isSpeaking ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                      title={isSpeaking ? "Stop Reading" : "Read Question"}
                    >
                      {isSpeaking ? <VolumeX size={14} /> : <Volume2 size={14} />}
                      {isSpeaking ? 'Stop' : 'Speak'}
                    </button>
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8">
                  {currentQ.data.questionText}
                </h2>

                <div className="flex flex-col lg:flex-row gap-8">
                  <div className={`flex-1 space-y-4 md:space-y-6 order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 hover:border-blue-300 hover:bg-slate-50 text-slate-700";
                      let icon = <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>;

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          icon = <CircleCheck className="text-emerald-600" size={20} />;
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          icon = <CircleX className="text-red-500" size={20} />;
                        } else {
                          containerClass = "border-slate-200 opacity-50";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-sm";
                        icon = <div className="w-5 h-5 rounded-full border-[6px] border-blue-600 bg-white"></div>;
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full text-left p-4 md:p-6 rounded-lg border-2 transition-all flex items-center gap-4 group ${containerClass}`}
                        >
                          <div className="shrink-0">{icon}</div>
                          <span className="font-medium text-base">{option}</span>
                        </button>
                      );
                    })}

                    {/* Immediate Feedback in Practice Mode */}
                    {hasAnsweredPractice && (
                      <div className="mt-6 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(currentQ.data.explanation || 'No explanation available.')}
                              className="text-slate-400 hover:text-slate-600"
                              title="Read Explanation"
                            >
                              <Volume2 size={16} />
                            </button>
                          </div>
                          <p className="text-slate-700 text-sm leading-relaxed">
                            {currentQ.data.explanation || "No explanation available for this question."}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Action Bar */}
              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useRef } from 'react';
import { Question } from '../types';
import { Shuffle, RotateCcw, Image as ImageIcon, CircleAlert, Eye, EyeOff, ChevronLeft, ChevronRight, Volume2, VolumeX, Lightbulb } from 'lucide-react';
import Button from './Button';

interface FlashcardsProps {
  data: Question[];
}

type AudioType = 'question' | 'answer' | 'explanation';

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  // Voice State
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [activeAudioType, setActiveAudioType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);
  const speakingRef = useRef<boolean>(false);
  const currentTextRef = useRef<string | null>(null);

  useEffect(() => {
    setDeck(data);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancelSpeech();
  }, [currentIndex, deck]);

  useEffect(() => {
    // We do not auto-cancel on flip anymore to allow listening while reading the other side,
    // unless the user wants to. But typically, flipping implies context switch. 
    // Let's keep audio playing if flipped, but visual indicators will update.
    // Actually, for better UX, let's stop audio on flip to avoid confusion.
    cancelSpeech();
  }, [isFlipped]);

  // Load voices
  useEffect(() => {
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      // Prefer high-quality US English voices
      const preferred = 
        voices.find(v => v.name.includes('Google US English')) || 
        voices.find(v => v.name.includes('Samantha')) || 
        voices.find(v => v.lang === 'en-US');

      setVoice(preferred || voices[0]);
    };

    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      cancelSpeech();
    };
  }, []);

  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setActiveAudioType(null);
      speakingRef.current = false;
      currentTextRef.current = null;
    }
  };

  const speak = (text: string, type: AudioType, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();

    if (!('speechSynthesis' in window)) return;

    // Smart Toggle Logic:
    // If we are currently speaking THIS exact text, stop it (Toggle behavior).
    // If we are speaking something else, stop that and start this (Switch behavior).
    if (speakingRef.current && currentTextRef.current === text) {
      cancelSpeech();
      return;
    }

    // Stop whatever was playing before
    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);
    if (voice) utterance.voice = voice;
    utterance.lang = 'en-US'; // Ensure correct pronunciation
    utterance.rate = 0.9; // Slightly slower for study
    utterance.pitch = 1;

    // Set references
    currentTextRef.current = text;

    utterance.onstart = () => {
      setIsSpeaking(true);
      setActiveAudioType(type);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      setActiveAudioType(null);
      speakingRef.current = false;
      currentTextRef.current = null;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      setActiveAudioType(null);
      speakingRef.current = false;
      currentTextRef.current = null;
    };

    window.speechSynthesis.speak(utterance);
  };

  const nextCard = () => {
    if (currentIndex < deck.length - 1 && !isAnimating) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 200);
    }
  };

  const prevCard = () => {
    if (currentIndex > 0 && !isAnimating) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 200);
    }
  };

  const shuffleDeck = () => {
    setIsFlipped(false);
    setTimeout(() => {
      const shuffled = [...deck].sort(() => Math.random() - 0.5);
      setDeck(shuffled);
      setCurrentIndex(0);
    }, 200);
  };

  const flipCard = () => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(!isFlipped);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const currentCard = deck[currentIndex];

  if (!currentCard) {
    return <div className="p-8 text-center text-slate-500">No cards available.</div>;
  }

  return (
    <div className="flex flex-col items-center justify-center max-w-3xl mx-auto w-full px-4 py-8">
      {/* Controls Header */}
      <div className="w-full flex justify-between items-center mb-6 px-2">
        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm">
          Card {currentIndex + 1} / {deck.length}
        </span>
        <Button 
          variant="ghost" 
          onClick={shuffleDeck} 
          title="Shuffle Deck"
          className="flex items-center gap-2 text-xs font-bold text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
        >
          <Shuffle size={14} /> Shuffle
        </Button>
      </div>

      {/* Card Container */}
      <div className="relative w-full aspect-[4/5] sm:aspect-[4/3] md:aspect-[16/9] cursor-pointer perspective-1000 z-10" onClick={flipCard}>
        <div className={`
            w-full h-full relative transform-style-3d transition-transform duration-500 ease-in-out
            ${isFlipped ? 'rotate-y-180' : ''}
          `}>

          {/* Front Side (Question) */}
          <div className="absolute inset-0 w-full h-full bg-white rounded-xl shadow-md border border-slate-200 backface-hidden flex flex-col overflow-hidden">
            <div className="px-6 pt-6 flex justify-between items-start">
              <div className="flex flex-col">
                <span className="text-xs font-bold uppercase tracking-wider text-red-500 mb-1">Question</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider bg-slate-50 px-2 py-0.5 rounded border border-slate-100 w-fit">
                  {currentCard.category || 'General'}
                </span>
              </div>
              <div className="flex items-center gap-2 text-slate-300">
                <button 
                  onClick={(e) => speak(currentCard.questionText, 'question', e)}
                  className={`p-2 rounded-full transition-all duration-300 ${isSpeaking && activeAudioType === 'question' ? 'text-blue-600 bg-blue-50 scale-110 ring-2 ring-blue-100' : 'text-slate-400 hover:bg-slate-100 hover:text-blue-600'}`}
                  title={isSpeaking && activeAudioType === 'question' ? "Stop Reading" : "Read Question"}
                >
                  {isSpeaking && activeAudioType === 'question' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                </button>
                <RotateCcw size={16} />
              </div>
            </div>

            <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
              {currentCard.questionImage && (
                <div className="flex-shrink-0 w-full flex items-center justify-center mb-6">
                  {imgError ? (
                    <div className="flex flex-col items-center justify-center p-6 bg-slate-50 rounded-lg border border-slate-200 text-slate-400 gap-2">
                      <ImageIcon size={24} />
                      <span className="text-xs font-medium">Image not available</span>
                    </div>
                  ) : (
                    <div className="p-2 bg-white rounded-lg border border-slate-100 shadow-sm max-h-[200px] overflow-hidden">
                      <img 
                        src={currentCard.questionImage} 
                        alt="Question" 
                        className="max-h-[180px] w-auto object-contain"
                        onError={() => setImgError(true)}
                      />
                    </div>
                  )}
                </div>
              )}
              <p className={`text-xl md:text-2xl font-bold text-center text-slate-800 leading-relaxed ${currentCard.questionImage ? '' : 'mt-4'}`}>
                {currentCard.questionText || "Identify this item"}
              </p>
            </div>

            <div className="h-10 flex items-center justify-center text-[10px] font-bold text-slate-300 uppercase tracking-widest pb-2">
              Click to reveal answer
            </div>
          </div>

          {/* Back Side (Answer) */}
          <div className="absolute inset-0 w-full h-full bg-slate-800 rounded-xl shadow-md border border-slate-700 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
            <div className="px-6 pt-6 flex justify-between items-center border-b border-slate-700/50 pb-4">
              <span className="text-xs font-bold uppercase tracking-wider text-blue-400">Answer</span>
              <div className="flex items-center gap-2 text-slate-600">
                <button 
                  onClick={(e) => speak(currentCard.answerText + (currentCard.explanation ? `. Note: ${currentCard.explanation}` : ''), 'answer', e)}
                  className={`p-2 rounded-full transition-all duration-300 ${isSpeaking && activeAudioType === 'answer' ? 'text-blue-400 bg-white/10 scale-110 ring-1 ring-blue-400/50' : 'text-slate-500 hover:bg-slate-700 hover:text-blue-400'}`}
                  title={isSpeaking && activeAudioType === 'answer' ? "Stop Reading" : "Read Answer"}
                >
                  {isSpeaking && activeAudioType === 'answer' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                </button>
                <RotateCcw size={16} />
              </div>
            </div>

            <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
              {currentCard.answerImage && (
                <div className="flex-shrink-0 w-full flex items-center justify-center mb-6">
                  {ansImgError ? (
                    <div className="flex flex-col items-center justify-center p-6 bg-white/5 rounded-lg border border-white/10 text-slate-500 gap-2">
                      <CircleAlert size={24} />
                      <span className="text-xs font-medium">Image not available</span>
                    </div>
                  ) : (
                    <div className="p-2 bg-white/5 rounded-lg border border-white/10 max-h-[200px] overflow-hidden">
                      <img 
                        src={currentCard.answerImage} 
                        alt="Answer" 
                        className="max-h-[180px] w-auto object-contain"
                        onError={() => setAnsImgError(true)}
                      />
                    </div>
                  )}
                </div>
              )}

              <p className="text-xl md:text-3xl font-bold text-center text-white leading-relaxed drop-shadow-sm mb-4">
                {currentCard.answerText}
              </p>

              {currentCard.explanation && (
                <div className="w-full max-w-lg mt-auto mb-2 animate-in slide-in-from-bottom-2 fade-in duration-300">
                  <div className="bg-slate-900/50 border border-slate-600/30 rounded-lg overflow-hidden">
                    <div className="px-4 py-2 bg-slate-800/50 border-b border-slate-700/50 flex justify-between items-center">
                      <span className="text-emerald-400 font-bold text-[10px] uppercase tracking-wider flex items-center gap-1.5">
                        <Lightbulb size={12} /> Explanation
                      </span>
                      <button 
                        onClick={(e) => speak(currentCard.explanation || '', 'explanation', e)}
                        className={`transition-colors p-1 rounded ${isSpeaking && activeAudioType === 'explanation' ? 'text-emerald-400 bg-emerald-400/20' : 'text-slate-400 hover:text-emerald-400'}`}
                        title={isSpeaking && activeAudioType === 'explanation' ? "Stop Explanation" : "Read Explanation Only"}
                      >
                        {isSpeaking && activeAudioType === 'explanation' ? <VolumeX size={12} /> : <Volume2 size={12} />}
                      </button>
                    </div>
                    <div className="p-4 text-slate-300 text-sm text-center leading-relaxed">
                      {currentCard.explanation}
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Navigation Controls */}
      <div className="flex items-center gap-6 mt-8 w-full justify-center max-w-md">
        <Button 
          variant="outline" 
          onClick={prevCard} 
          disabled={currentIndex === 0 || isAnimating}
          className="w-12 h-12 rounded-full border-slate-200 text-slate-400 hover:text-slate-600 hover:border-slate-300 disabled:opacity-30 bg-white shadow-sm"
        >
          <ChevronLeft size={24} />
        </Button>

        <Button 
          variant="primary" 
          onClick={flipCard}
          disabled={isAnimating}
          className={`
            h-12 px-6 rounded-full font-bold shadow-md transition-all active:scale-95 flex items-center gap-2
            ${isFlipped ? 'bg-slate-700 hover:bg-slate-600 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}
          `}
        >
          {isFlipped ? <><EyeOff size={18} /> Hide </> : <><Eye size={18} /> Show </>}
        </Button>

        <Button 
          variant="secondary" 
          onClick={nextCard} 
          disabled={currentIndex === deck.length - 1 || isAnimating}
          className="w-12 h-12 rounded-full bg-white text-blue-600 border border-slate-200 hover:bg-blue-50 hover:border-blue-200 disabled:opacity-30 shadow-sm"
        >
          <ChevronRight size={24} />
        </Button>
      </div>
    </div>
  );
};

