import React, { useState, useEffect, useRef } from 'react';
import { Question } from '../types';
import { Search, Image as ImageIcon, Volume2, VolumeX } from 'lucide-react';

interface QuestionListProps {
  data: Question[];
}

const QuestionList: React.FC<QuestionListProps> = ({ data }) => {
  const [search, setSearch] = useState('');

  // Audio State
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  // Voice Loading
  useEffect(() => {
    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const preferred = 
        voices.find(v => v.name.includes('Google US English')) || 
        voices.find(v => v.name.includes('Samantha')) || 
        voices.find(v => v.lang === 'en-US');
      setVoice(preferred || voices[0]);
    };

    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      cancelSpeech();
    };
  }, []);

  const cancelSpeech = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  };

  const speak = (text: string, id: string) => {
    if (!('speechSynthesis' in window)) return;

    if (speakingRef.current && activeUtteranceId.current === id) {
      cancelSpeech();
      return;
    }

    cancelSpeech();

    const utterance = new SpeechSynthesisUtterance(text);
    if (voice) utterance.voice = voice;
    utterance.lang = 'en-US';
    utterance.rate = 1.0;
    utterance.pitch = 1;

    activeUtteranceId.current = id;

    utterance.onstart = () => {
      setIsSpeaking(true);
      setSpeakingId(id);
      speakingRef.current = true;
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      setSpeakingId(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      setSpeakingId(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    };

    window.speechSynthesis.speak(utterance);
  };

  const filtered = data.filter(q => 
    q.questionText.toLowerCase().includes(search.toLowerCase()) || 
    q.answerText.toLowerCase().includes(search.toLowerCase()) ||
    q.category?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="max-w-5xl mx-auto w-full px-4 py-8">
      <div className="mb-6">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Search terms, definitions, or categories..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 shadow-sm outline-none bg-white text-slate-700 placeholder:text-slate-400"
          />
        </div>
        <div className="mt-2 text-sm text-slate-500 text-right">
          Showing {filtered.length} of {data.length} terms
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 font-bold text-slate-600 text-xs uppercase tracking-wider w-1/3">Term / Question</th>
                <th className="px-6 py-4 font-bold text-slate-600 text-xs uppercase tracking-wider">Definition / Answer</th>
                <th className="px-6 py-4 font-bold text-slate-600 text-xs uppercase tracking-wider w-32">Category</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map((q) => (
                <tr key={q.id} className="hover:bg-blue-50/50 transition-colors group">
                  <td className="px-6 py-4 align-top">
                    <div className="flex flex-col gap-2">
                      <div className="flex items-start gap-2">
                        <button 
                          onClick={() => speak(q.questionText, `term-${q.id}`)}
                          className={`mt-0.5 p-1 rounded-full transition-colors shrink-0 ${isSpeaking && speakingId === `term-${q.id}` ? 'text-blue-600 bg-blue-100' : 'text-slate-300 hover:text-blue-500 hover:bg-slate-100'}`}
                          title="Listen to term"
                        >
                          {isSpeaking && speakingId === `term-${q.id}` ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        </button>
                        <span className="font-medium text-slate-900">{q.questionText}</span>
                      </div>
                      {q.questionImage && (
                        <div className="relative group/img w-16 h-16 bg-slate-100 rounded border border-slate-200 overflow-hidden shrink-0 cursor-pointer ml-7">
                          <img src={q.questionImage} alt="Q" className="w-full h-full object-cover" />
                          <div className="absolute inset-0 bg-black/0 group-hover/img:bg-black/10 transition-colors flex items-center justify-center">
                            <ImageIcon size={16} className="text-white opacity-0 group-hover/img:opacity-100" />
                          </div>
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 align-top">
                    <div className="flex flex-col gap-2">
                      <div className="flex items-start gap-2">
                        <button 
                          onClick={() => speak(q.answerText, `def-${q.id}`)}
                          className={`mt-0.5 p-1 rounded-full transition-colors shrink-0 ${isSpeaking && speakingId === `def-${q.id}` ? 'text-blue-600 bg-blue-100' : 'text-slate-300 hover:text-blue-500 hover:bg-slate-100'}`}
                          title="Listen to definition"
                        >
                          {isSpeaking && speakingId === `def-${q.id}` ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        </button>
                        <span className="text-slate-600">{q.answerText}</span>
                      </div>
                      {q.answerImage && (
                        <div className="mt-2 ml-7">
                          <img src={q.answerImage} alt="A" className="max-h-32 rounded border border-slate-200" />
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 align-top">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide bg-red-50 text-red-700 border border-red-100">
                      {q.category || 'General'}
                    </span>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-500 italic">
                    No results found for "{search}"
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

