              </div>
              <div className="flex items-center gap-2 text-slate-300">
                <button 
                  onClick={(e) => speak(currentCard.questionText, 'question-main', 'question', e)}
                  className={`p-2 rounded-full transition-all duration-300 ${isSpeaking && activeType === 'question' ? 'text-blue-600 bg-blue-50 scale-110 ring-2 ring-blue-100 animate-pulse' : 'text-slate-400 hover:bg-slate-100 hover:text-blue-600'}`}
