                  {imgError ? (
                    <div className="flex flex-col items-center justify-center p-6 bg-slate-50 rounded-lg border border-slate-200 text-slate-400 gap-2">
                      <ImageIcon size={24} />
                      <span className="text-xs font-medium">Image not available</span>
