import { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  // Advanced Voice Loading Logic
  useEffect(() => {
    const loadVoices = () => {
      if (typeof window === 'undefined' || !window.speechSynthesis) return;

      const voices = window.speechSynthesis.getVoices();

      // Priority list for better clarity (Anatomy terms need clear en-US pronunciation)
      const preferred = 
        voices.find(v => v.name === 'Google US English') || 
        voices.find(v => v.name === 'Microsoft Zira Desktop - English (United States)') || 
        voices.find(v => v.name === 'Samantha') || 
        voices.find(v => v.lang === 'en-US' && v.localService) || // Prefer local/offline voices for speed
        voices.find(v => v.lang === 'en-US');

      setVoice(preferred || voices[0]);
    };

    loadVoices();

    // Chrome loads voices asynchronously
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();

    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    // Toggle logic: If clicking the same button that is currently speaking, stop it.
    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    // Stop any previous speech immediately
    // This triggers onerror on the previous utterance with error='interrupted' or 'canceled'
    cancel();

    // Clean text for better pronunciation (remove some special chars if needed, add pauses)
    const cleanText = text.replace(/([.:;?!])/g, '$1 '); 

    const utterance = new SpeechSynthesisUtterance(cleanText);

    if (voice) utterance.voice = voice;

    utterance.lang = 'en-US';
    // Slightly slower rate for clearer anatomical pronunciation
    utterance.rate = 0.9; 
    utterance.pitch = 1.0;
    utterance.volume = 1.0;

    // Mark this ID as the active intent
    activeUtteranceId.current = id;

    utterance.onstart = () => {
      // Only update state if this utterance is still the intended one
      if (activeUtteranceId.current === id) {
        setIsSpeaking(true);
        setSpeakingId(id);
        setActiveType(type);
        speakingRef.current = true;
      }
    };

    utterance.onend = () => {
      if (activeUtteranceId.current === id) {
        setIsSpeaking(false);
        setSpeakingId(null);
        setActiveType(null);
        speakingRef.current = false;
        activeUtteranceId.current = null;
      }
    };

    utterance.onerror = (event) => {
      // Ignore errors caused by manual cancellation/interruption
      if (event.error === 'interrupted' || event.error === 'canceled') {
        return;
      }

      console.error("Speech synthesis error", event);

      if (activeUtteranceId.current === id) {
        setIsSpeaking(false);
        setSpeakingId(null);
        setActiveType(null);
        speakingRef.current = false;
        activeUtteranceId.current = null;
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

import { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  // Advanced Voice Loading Logic
  useEffect(() => {
    const loadVoices = () => {
      if (typeof window === 'undefined' || !window.speechSynthesis) return;

      const voices = window.speechSynthesis.getVoices();

      // Priority list for better clarity (Anatomy terms need clear en-US pronunciation)
      const preferred = 
        voices.find(v => v.name === 'Google US English') || 
        voices.find(v => v.name === 'Samantha') || 
        voices.find(v => v.name === 'Microsoft Zira Desktop - English (United States)') || 
        voices.find(v => v.name.includes('English United States')) ||
        voices.find(v => v.lang === 'en-US' && v.localService) || // Prefer local/offline voices for speed
        voices.find(v => v.lang === 'en-US');

      setVoice(preferred || voices[0]);
    };

    loadVoices();

    // Chrome loads voices asynchronously
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();

    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    // Toggle logic: If clicking the same button that is currently speaking, stop it.
    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    // Stop any previous speech immediately
    cancel();

    // Clean text for better pronunciation (replace symbols, add pauses)
    const cleanText = text
      .replace(/\//g, ' or ')
      .replace(/&/g, ' and ')
      .replace(/\+/g, ' plus ')
      .replace(/(\d+)-(\d+)/g, '$1 to $2') // Ranges like 10-20
      .replace(/([.:;?!])/g, '$1 '); // Ensure space after punctuation for flow

    // Chunking Strategy: Split text into sentences to avoid browser timeouts on long text
    // Matches sentences ending with . ! ? or end of string
    const chunks = cleanText.match(/[^.!?]+[.!?]+(?=\s|$)|[^.!?]+$/g) || [cleanText];
    const filteredChunks = chunks.map(c => c.trim()).filter(c => c.length > 0);

    // If no text, return
    if (filteredChunks.length === 0) return;

    // Set state immediately
    activeUtteranceId.current = id;
    speakingRef.current = true;
    setIsSpeaking(true);
    setSpeakingId(id);
    setActiveType(type);

    filteredChunks.forEach((chunk, index) => {
      const utterance = new SpeechSynthesisUtterance(chunk);

      if (voice) utterance.voice = voice;

      utterance.lang = 'en-US';
      utterance.rate = 0.9; // Slightly slower for better clarity
      utterance.pitch = 1.0;
      utterance.volume = 1.0;

      // Only the last chunk's end event should reset the state
      if (index === filteredChunks.length - 1) {
        utterance.onend = () => {
          if (activeUtteranceId.current === id) {
            setIsSpeaking(false);
            setSpeakingId(null);
            setActiveType(null);
            speakingRef.current = false;
            activeUtteranceId.current = null;
          }
        };
      }

      utterance.onerror = (event) => {
        // Ignore interruption errors (caused by cancel())
        if (event.error === 'interrupted' || event.error === 'canceled') {
          return;
        }

        console.error("Speech synthesis error", event);

        // Reset state on actual error
        if (activeUtteranceId.current === id) {
          setIsSpeaking(false);
          setSpeakingId(null);
          setActiveType(null);
          speakingRef.current = false;
          activeUtteranceId.current = null;
        }
      };

      // Queue the utterance
      window.speechSynthesis.speak(utterance);
    });

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

