          activeUtteranceId.current = null;
        }
      };

      window.speechSynthesis.speak(utterance);
    });

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

import { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  // Advanced Voice Loading Logic
  useEffect(() => {
    const loadVoices = () => {
      if (typeof window === 'undefined' || !window.speechSynthesis) return;

      let voices = window.speechSynthesis.getVoices();

      // Filter for English voices only
      voices = voices.filter(v => v.lang.startsWith('en'));

      // Priority list for High Quality / Natural Voices
      const preferred = 
        voices.find(v => v.name.includes('Natural') && v.lang === 'en-US') || // Edge US Natural
        voices.find(v => v.name.includes('Natural')) || // Any Natural
        voices.find(v => v.name.includes('Premium')) || // Mobile Premium
        voices.find(v => v.name.includes('Enhanced')) || // Apple Enhanced
        voices.find(v => v.name === 'Google US English') || // Chrome Standard
        voices.find(v => v.name === 'Samantha') || // macOS Standard
        voices.find(v => v.name.includes('Zira')) || // Windows Standard
        voices.find(v => v.lang === 'en-US' && v.localService) || 
        voices.find(v => v.lang === 'en-US') ||
        voices[0]; // Fallback

      setVoice(preferred || null);
    };

    loadVoices();

    // Chrome loads voices asynchronously
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();

    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    // Toggle logic
    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    cancel();

    // Clean text: Improved for natural pauses and clarity
    const cleanText = text
      .replace(/\//g, ' or ')
      .replace(/&/g, ' and ')
      .replace(/\+/g, ' plus ')
      .replace(/=/g, ' equals ')
      .replace(/(\d+)-(\d+)/g, '$1 to $2') 
      .replace(/([.:;?!])/g, '$1 ') // Ensure space after punctuation
      .replace(/[\(\[\{]/g, ', ') // Pause before brackets/parentheses
      .replace(/[\)\]\}]/g, ', '); // Pause after brackets/parentheses

    // Chunking: Essential for browser stability with long text
    const chunks = cleanText.match(/[^.!?]+[.!?]+(?=\s|$)|[^.!?]+$/g) || [cleanText];
    const filteredChunks = chunks.map(c => c.trim()).filter(c => c.length > 0);

    if (filteredChunks.length === 0) return;

    activeUtteranceId.current = id;
    speakingRef.current = true;
    setIsSpeaking(true);
    setSpeakingId(id);
    setActiveType(type);

    filteredChunks.forEach((chunk, index) => {
      const utterance = new SpeechSynthesisUtterance(chunk);

      if (voice) {
        utterance.voice = voice;
        utterance.lang = voice.lang; // Important: Match voice language
      } else {
        utterance.lang = 'en-US';
      }

      // Smart Rate: Slower is clearer for anatomy terms
      const isHighQuality = voice && (voice.name.includes('Natural') || voice.name.includes('Premium') || voice.name.includes('Enhanced'));

      // 0.9 for Natural voices (they are usually clear), 0.85 for robotic/standard ones to ensure enunciation
      utterance.rate = isHighQuality ? 0.9 : 0.85; 

      utterance.pitch = 1.0;
      utterance.volume = 1.0;

      if (index === filteredChunks.length - 1) {
        utterance.onend = () => {
          if (activeUtteranceId.current === id) {
            setIsSpeaking(false);
            setSpeakingId(null);
            setActiveType(null);
            speakingRef.current = false;
            activeUtteranceId.current = null;
          }
        };
      }

      utterance.onerror = (event) => {
        if (event.error === 'interrupted' || event.error === 'canceled') return;
        console.error("Speech synthesis error", event);

        if (activeUtteranceId.current === id) {
          setIsSpeaking(false);
          setSpeakingId(null);
          setActiveType(null);
          speakingRef.current = false;
          activeUtteranceId.current = null;
        }
      };

      window.speechSynthesis.speak(utterance);
    });

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
