    ---------------------------------- */

    let confettiPieces = [];
    const colors = ['#ff6f61', '#6c5ce7', '#00b894', '#ffeaa7', '#0984e3', '#fab1a0', '#2d3436'];

    const originX = rect.width / 2;
    const originY = rect.height - 5;

    for (let i = 0; i < 250; i++) {
        const shape = ['rect', 'circle', 'oval', 'star', 'heart'][Math.floor(Math.random() * 5)];
        const color =
            shape === 'star' ? '#FFD700' :
            shape === 'heart' ? '#FF0000' :
            colors[Math.floor(Math.random() * colors.length)];

        const angle = (Math.PI / 2) + (Math.random() * Math.PI / 1.5 - Math.PI / 3);
        const speed = Math.random() * 6 + 6;

        confettiPieces.push({
            x: originX,
            y: originY,
            size: Math.random() * 5 + 2,
            color: color,
            speedX: Math.cos(angle) * speed,
            speedY: -Math.sin(angle) * speed * 1.5,
            rotation: Math.random() * 360,
            rotationSpeed: Math.random() * 6 - 3,
            gravity: 0.25,
            opacity: 1,
            shape: shape
        });
    }

    function drawStar(ctx, size) {
        ctx.beginPath();
        for (let i = 0; i < 5; i++) {
            ctx.lineTo(
                Math.cos((18 + i * 72) * Math.PI / 180) * size,
                -Math.sin((18 + i * 72) * Math.PI / 180) * size
            );
            ctx.lineTo(
                Math.cos((54 + i * 72) * Math.PI / 180) * size / 2,
                -Math.sin((54 + i * 72) * Math.PI / 180) * size / 2
            );
        }
        ctx.closePath();
        ctx.fill();
    }

    function drawHeart(ctx, size) {
        ctx.beginPath();
        const topCurve = size * 0.3;
        ctx.moveTo(0, size / 4);
        ctx.bezierCurveTo(size / 2, -topCurve, size, size / 2, 0, size);
        ctx.bezierCurveTo(-size, size / 2, -size / 2, -topCurve, 0, size / 4);
        ctx.closePath();
        ctx.fill();
    }

    function animate() {
        ctx.clearRect(0, 0, rect.width, rect.height);

        confettiPieces.forEach((p, index) => {
            p.x += p.speedX;
            p.y += p.speedY;
            p.speedY += p.gravity;
            p.rotation += p.rotationSpeed;
            p.opacity -= 0.002;

            ctx.save();
            ctx.translate(p.x, p.y);
            ctx.rotate(p.rotation * Math.PI / 180);
            ctx.globalAlpha = p.opacity;
            ctx.fillStyle = p.color;

            if (p.shape === 'rect') {
                ctx.fillRect(-p.size / 2, -p.size / 4, p.size, p.size * 0.4);
            } else if (p.shape === 'circle') {
                ctx.beginPath();
                ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
                ctx.fill();
            } else if (p.shape === 'oval') {
                ctx.scale(1.5, 1);
                ctx.beginPath();
                ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
                ctx.fill();
                ctx.setTransform(1, 0, 0, 1, 0, 0);
            } else if (p.shape === 'star') {
                drawStar(ctx, p.size);
            } else if (p.shape === 'heart') {
                drawHeart(ctx, p.size);
            }

            ctx.restore();
            if (p.opacity <= 0 || p.y > rect.height + 20) confettiPieces.splice(index, 1);
        });

        if (confettiPieces.length > 0) requestAnimationFrame(animate);
    }

    animate();

    setTimeout(() => canvas.remove(), 3000);
}

